document.addEventListener("DOMContentLoaded",()=>{if(!document.body.classList.contains("lookbook-page"))return;const e=[...document.querySelectorAll("[data-reveal]")].filter(e=>!e.closest(".site-footer")),t=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&(e.target.classList.add("revealed"),t.unobserve(e.target))})},{threshold:.08,rootMargin:"0px 0px -40px 0px"});e.forEach(e=>t.observe(e));const o=document.querySelectorAll(".lb-video");if("IntersectionObserver"in window){const e=new IntersectionObserver(t=>{t.forEach(t=>{if(t.isIntersecting){const o=t.target,r=o.querySelector("source");r&&!r.dataset.loaded&&(o.load(),r.dataset.loaded="true"),o.play().catch(()=>{}),e.unobserve(o)}})},{threshold:.2});o.forEach(t=>e.observe(t))}const r=document.querySelector(".lb-hero"),s=document.querySelector(".lb-hero-image");if(r&&s){const e=()=>{const e=window.scrollY,t=r.offsetHeight;if(e<=t){const o=e/t;s.style.transform=`translateY(${20*o}px) scale(${1+.02*o})`}};window.addEventListener("scroll",e,{passive:!0}),e()}});